import './Checkbox.scss';

import { Icons } from '@beeline/design-tokens/js/iconfont/icons';
import React from 'react';

import { classNames } from '../../helpers/classnames';
import { Icon } from '../Icon';
import { Typography } from '../Typography';
import type { CheckboxProps } from './Checkbox.types';

export const Checkbox = React.forwardRef<HTMLInputElement, CheckboxProps>(
	({ checked, className, type, label, disabled, error = false, dataTestId = 'Checkbox', ...props }, ref) => (
		<label
			data-testid={dataTestId}
			className={classNames('dsb_checkbox', disabled && 'disabled', error && 'dsb_checkbox__error', className)}
		>
			<span className="dsb_checkbox-root">
				<input
					type="checkbox"
					checked={checked}
					disabled={disabled}
					aria-invalid={error}
					{...props}
					className="dsb_checkbox-input"
					ref={ref}
				/>
				<Icon
					className="dsb_checkbox-icon"
					size="large"
					iconName={type === 'indeterminate' ? Icons.Remove : Icons.Check}
				/>
			</span>

			{label && (
				<>
					{typeof label === 'string' ? (
						<Typography variant="body2" className="dsb_checkbox-label">
							{label}
						</Typography>
					) : (
						label
					)}
				</>
			)}
		</label>
	),
);
